          <div style={{background:'#FEF2F2',borderRadius:12,padding:16,borderLeft:`3px solid ${C.error}`}}>
            <div style={{fontSize:11,fontWeight:700,color:C.gray,letterSpacing:0.5}}>QUICKBITE CUT (10%)</div>
            <div style={{fontSize:22,fontWeight:800,color:C.error,margin:'4px 0'}}>₦{Math.round(platformCut).toLocaleString()}</div>
            <div style={{fontSize:12,color:C.gray}}>Platform service fee</div>
          </div>
          <div style={{background:'#EFF6FF',borderRadius:12,padding:16,borderLeft:`3px solid #3B82F6`}}>
            <div style={{fontSize:11,fontWeight:700,color:C.gray,letterSpacing:0.5}}>YOUR NET EARNINGS</div>
            <div style={{fontSize:22,fontWeight:800,color:'#3B82F6',margin:'4px 0'}}>₦{(data?.allTimeRevenue||0).toLocaleString()}</div>
            <div style={{fontSize:12,color:C.gray}}>90% of food orders</div>
          </div>
        </div>
      </div>

      {/* Wallet & Withdrawal */}
      <div style={{...card,borderTop:`3px solid ${C.success}`,marginBottom:20}}>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16}}>
          <div>
            <h3 style={{fontWeight:800,marginBottom:4}}>💰 Wallet & Withdrawal</h3>
            <p style={{color:C.gray,fontSize:13}}>Request a withdrawal — processed via Paystack to your bank account</p>
          </div>
          <div style={{textAlign:'right'}}>
            <div style={{fontSize:11,fontWeight:700,color:C.gray}}>AVAILABLE BALANCE</div>
            <div style={{fontSize:28,fontWeight:800,color:C.success}}>₦{(data?.walletBalance||0).toLocaleString()}</div>
          </div>
        </div>
        {!showWForm?(
          <button style={{...btn(C.success),padding:'10px 24px',fontSize:14}} onClick={()=>setShowWForm(true)}>↗ Request Withdrawal</button>
        ):(
          <div>
            <div style={{display:'flex',gap:12,alignItems:'flex-end',marginBottom:10}}>
              <div style={{flex:1}}>
                <label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Amount to withdraw (₦)</label>
                <input style={inp} type="number" placeholder="e.g. 10000" value={wAmount} onChange={e=>setWAmount(e.target.value)} />
              </div>
              <button style={{...btn(C.success),padding:'10px 24px',fontSize:14,whiteSpace:'nowrap'}} onClick={requestWithdrawal} disabled={wLoading}>
                {wLoading?'Requesting...':'✓ Submit Request'}
              </button>
              <button style={{...btn('#f5f5f5'),color:C.gray,padding:'10px 16px'}} onClick={()=>setShowWForm(false)}>Cancel</button>
            </div>
            <p style={{color:C.gray,fontSize:12}}>⚠️ Make sure your bank details are saved in Settings before requesting a withdrawal.</p>
          </div>
        )}
      </div>

      {/* Withdrawal history */}
      {withdrawals.length>0&&(
        <div style={{...card,marginBottom:20}}>
          <h3 style={{fontWeight:800,marginBottom:14}}>Withdrawal History</h3>
          {withdrawals.map(w=>(
            <div key={w._id} style={{display:'flex',justifyContent:'space-between',alignItems:'center',paddingBottom:12,marginBottom:12,borderBottom:`1px solid ${C.border}`}}>
              <div>
                <div style={{fontWeight:700,fontSize:15}}>₦{w.amount?.toLocaleString()}</div>
                <div style={{color:C.gray,fontSize:12}}>{new Date(w.createdAt).toLocaleDateString()} · {w.bankDetails?.bankName} {w.bankDetails?.accountNumber}</div>
                {w.adminNote&&<div style={{color:C.warning,fontSize:12,marginTop:2}}>Note: {w.adminNote}</div>}
              </div>
              <span style={{background:(SC[w.status]||C.gray)+'22',color:SC[w.status]||C.gray,padding:'4px 14px',borderRadius:20,fontSize:13,fontWeight:700,textTransform:'capitalize'}}>{w.status}</span>
            </div>
          ))}
        </div>
      )}

      {/* Top items */}
      <div style={card}>
        <h3 style={{fontWeight:800,marginBottom:16}}>🏆 Top Menu Items</h3>
        {top.map(([name,count],i)=>(
          <div key={name} style={{display:'flex',alignItems:'center',gap:12,marginBottom:14}}>
            <span style={{width:20,color:C.gray,fontWeight:800}}>{i+1}</span>
            <span style={{width:160,fontWeight:600}}>{name}</span>
            <div style={{flex:1,height:8,background:'#f5f5f5',borderRadius:4}}><div style={{width:`${(count/382)*100}%`,height:'100%',background:C.primary,borderRadius:4}} /></div>
            <span style={{color:C.gray,fontWeight:700,width:40,textAlign:'right'}}>{count}×</span>
          </div>
        ))}
      </div>

      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>
        <div style={card}><div style={{color:C.gray,fontSize:11,fontWeight:700}}>AVG ORDER VALUE</div><div style={{fontSize:28,fontWeight:800,margin:'4px 0'}}>₦{data?.allTimeOrders>0?Math.floor((data?.allTimeRevenue||0)/(data?.allTimeOrders||1)).toLocaleString():0}</div><div style={{color:C.gray,fontSize:12}}>per order (your 90%)</div></div>
        <div style={card}><div style={{color:C.gray,fontSize:11,fontWeight:700}}>TOTAL ORDERS</div><div style={{fontSize:28,fontWeight:800,margin:'4px 0'}}>{data?.allTimeOrders||0}</div><div style={{color:C.gray,fontSize:12}}>all time delivered</div></div>
      </div>
    </div>
  );
}

function Settings() {
  const {restaurant,setRestaurant}=useAuth();
  const [form,setForm]=useState({name:'',phone:'',address:'',cuisineType:'',description:'',isOpen:false,openTime:'08:00',closeTime:'22:00'});
  const [bankForm,setBankForm]=useState({bankName:'',accountNumber:'',accountName:'',bankCode:''});
  const [saving,setSaving]=useState(false);
  const [savingBank,setSavingBank]=useState(false);

  useEffect(()=>{
    if(restaurant){
      setForm({name:restaurant.name||'',phone:restaurant.phone||'',address:restaurant.address||'',cuisineType:restaurant.cuisineType||'',description:restaurant.description||'',isOpen:restaurant.isOpen||false,openTime:restaurant.openTime||'08:00',closeTime:restaurant.closeTime||'22:00'});
      if(restaurant.bankDetails) setBankForm(restaurant.bankDetails);
    }
  },[restaurant]);

  const save=async()=>{
    setSaving(true);
    try{ const {data}=await api.patch('/restaurants/me',form); setRestaurant(data); alert('Settings saved!'); }
    catch{ alert('Failed to save'); }finally{ setSaving(false); }
  };

  const saveBank=async()=>{
    if(!bankForm.accountNumber||!bankForm.bankName||!bankForm.accountName) return alert('Fill in all bank details');
    setSavingBank(true);
    try{ const {data}=await api.patch('/restaurants/me',{bankDetails:bankForm}); setRestaurant(data); alert('Bank details saved!'); }
    catch{ alert('Failed to save bank details'); }finally{ setSavingBank(false); }
  };

  return (
    <div style={{padding:28,overflowY:'auto',flex:1}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:24}}>
        <h1 style={{fontSize:26,fontWeight:800}}>Settings</h1>
        <button style={btn(C.primary)} onClick={save} disabled={saving}>{saving?'Saving...':'💾 Save Changes'}</button>
      </div>

      {/* Status */}
      <div style={{...card,marginBottom:16}}>
        <h3 style={{fontWeight:800,marginBottom:14}}>🟢 Restaurant Status</h3>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:4}}>
          <span style={{fontWeight:600}}>Currently {form.isOpen?'Open':'Closed'}</span>
          <input type="checkbox" checked={form.isOpen} onChange={e=>setForm({...form,isOpen:e.target.checked})} style={{width:22,height:22,cursor:'pointer',accentColor:C.primary}} />
        </div>
        <p style={{color:C.gray,fontSize:13,marginBottom:14}}>{form.isOpen?'Accepting orders from customers':'Not accepting orders'}</p>
        <div style={{display:'grid',gridTemplateColumns:'1fr auto 1fr',gap:12,alignItems:'end'}}>
          <div><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Opens</label><input style={inp} value={form.openTime} onChange={e=>setForm({...form,openTime:e.target.value})} /></div>
          <span style={{paddingBottom:10,color:C.gray,fontWeight:700}}>→</span>
          <div><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Closes</label><input style={inp} value={form.closeTime} onChange={e=>setForm({...form,closeTime:e.target.value})} /></div>
        </div>
      </div>

      {/* Restaurant details */}
      <div style={{...card,marginBottom:16}}>
        <h3 style={{fontWeight:800,marginBottom:14}}>🏪 Restaurant Details</h3>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>
          {[['Restaurant Name','name'],['Phone','phone'],['Address','address'],['Cuisine Type','cuisineType']].map(([l,k])=>(
            <div key={k}><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>{l}</label><input style={inp} value={form[k]} onChange={e=>setForm({...form,[k]:e.target.value})} /></div>
          ))}
        </div>
        <div style={{marginTop:14}}><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Description</label><textarea style={{...inp,height:90,resize:'vertical'}} value={form.description} onChange={e=>setForm({...form,description:e.target.value})} /></div>
      </div>

      {/* Bank details */}
      <div style={{...card,borderTop:`3px solid ${C.success}`}}>
        <h3 style={{fontWeight:800,marginBottom:4}}>🏦 Bank Details for Withdrawals</h3>
        <p style={{color:C.gray,fontSize:13,marginBottom:16}}>Required to receive withdrawal payments via Paystack</p>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14,marginBottom:14}}>
          {[['Bank Name','bankName','e.g. GTBank'],['Account Number','accountNumber','10-digit number'],['Account Name','accountName','As on bank records'],['Bank Code','bankCode','e.g. 058 for GTBank']].map(([l,k,p])=>(
            <div key={k}>
              <label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>{l}</label>
              <input style={inp} placeholder={p} value={bankForm[k]} onChange={e=>setBankForm({...bankForm,[k]:e.target.value})} keyboardType={k==='accountNumber'||k==='bankCode'?'numeric':'text'} />
            </div>
          ))}
        </div>
        <button style={{...btn(C.success),padding:'10px 24px',fontSize:14}} onClick={saveBank} disabled={savingBank}>
          {savingBank?'Saving...':'✓ Save Bank Details'}
        </button>
      </div>
    </div>
  );
}

function AppContent() {
  const {user}=useAuth();
  const [page,setPage]=useState('overview');
  const [pendingCount,setPendingCount]=useState(0);
  useEffect(()=>{ if(user) api.get('/orders/restaurant').then(r=>setPendingCount(r.data.filter(o=>o.status==='pending').length)).catch(()=>{}); },[user]);
  if(!user) return <Login />;
  const pages={overview:<Overview setPage={setPage}/>,orders:<Orders/>,menu:<Menu/>,analytics:<Analytics/>,settings:<Settings/>};
  return (
    <div style={{display:'flex',width:'100%'}}>
      <Sidebar page={page} setPage={setPage} pendingCount={pendingCount} />
      <div style={{flex:1,overflowY:'auto',background:'#F8F8F8'}}>{pages[page]||<Overview setPage={setPage}/>}</div>
    </div>
  );
}

export default function App() { return <AuthProvider><AppContent /></AuthProvider>; }
